INSERT INTO `v1_3df042014b1acf44ce09edff37fa96f6304d653ac5d7c2506107430329b34105` VALUES ("スタンダードコレクション", 3, 1, "1回メダル{0}枚！\n定番グッズであなたの部屋をカルミナで彩ろう！", 1, "スタンダードコレクションではポスターやペナントなど\n部屋に飾れる定番グッズが盛りだくさん！\nあなたの部屋をカルミナで彩ろう！");
INSERT INTO `v1_3df042014b1acf44ce09edff37fa96f6304d653ac5d7c2506107430329b34105` VALUES ("プレミアムコレクション", 10, 1, "1回メダル{0}枚！\nメンバー直筆サイン色紙など、★★以上のグッズを確定でゲット！", 2, "プレミアムコレクションではサイン色紙や\nブロマイドなど、★★以上のグッズが盛りだくさん！\nレアグッズをたくさんゲットしよう！");
INSERT INTO `v1_3df042014b1acf44ce09edff37fa96f6304d653ac5d7c2506107430329b34105` VALUES ("フェスコレクション", 3, 1, "1回メダル{0}枚！\nカルミナライブに参加する際のマストアイテムをゲットしよう！", 3, "フェスコレクションではカルミナサマーライブで\n大活躍するグッズが勢ぞろい！\nゲットしたグッズを片手に、いざライブ会場へ！");
